+}
+
+function detectFormat(filePath: string): "mp3" | "opus" | "wav" | null {
+  const ext = path.extname(filePath).toLowerCase();
+  if (ext === ".opus" || ext === ".ogg") {
+    return "opus";
+  }
+  if (ext === ".wav") {
+    return "wav";
+  }
+  if (ext === ".mp3" || ext === ".m4a") {
+    return "mp3";
+  }
+  return null;
+}
+
+function getFileExt(format: string): string {
+  if (format === "opus") {
