+  }
+  if (format === "wav") {
+    return ".wav";
+  }
+  return ".mp3";
+}
+
+async function runCli(params: {
+  command: string;
+  args: string[];
+  cwd?: string;
+  env?: Record<string, string>;
+  timeoutMs: number;
+  text: string;
+  outputDir: string;
+  filePrefix: string;
+  outputFormat?: OutputFormat;
