+
+async function convertToRawPcm(inputPath: string, outputDir: string): Promise<Buffer> {
+  // Output raw 16kHz mono 16-bit little-endian PCM (no WAV headers)
+  const outputPath = path.join(outputDir, "telephony.pcm");
